INSERT INTO public.vocab_words (id, word, meaning, urdu_meaning, synonyms, antonyms, example, category, is_public)
VALUES
  ('vocab-101', 'Acrimonious', 'Angry and bitter, especially in speech or manner.', 'تلخ / کڑوا / طیش آلود (Talkh / Karwa / Tayash-aalood)', '["bitter","hostile","caustic","vitriolic"]', '["amicable","cordial","pleasant","harmonious"]', 'The acrimonious debate in the provincial assembly delayed the new education bill by three months.', 'CSS Vocab', true),
  
  ('vocab-102', 'Pejorative', 'Expressing contempt or disapproval.', 'تحقیری / توہین آمیز (Tahqeeri / Toheen-ameez)', '["derogatory","disparaging","defamatory","insulting"]', '["complimentary","praising","flattering"]', 'The candidate lost marks in the CSS interview for using a pejorative term when discussing rural development policies.', 'CSS Vocab', true),

  ('vocab-103', 'Recalcitrant', 'Having an obstinately uncooperative attitude toward authority or discipline.', 'سرکش / نافرمان (Sarkash / Nafarman)', '["uncooperative","intractable","obstreperous","truculent"]', '["docile","compliant","amenable","obedient"]', 'The recalcitrant suspect refused to cooperate with the FIA cybercrime wing during the digital forensics audit.', 'CSS Vocab', true),

  ('vocab-104', 'Truculent', 'Eager or quick to argue or fight; aggressively defiant.', 'لڑاکا / وحشیانہ (Laraka / Wahshiyana)', '["defiant","aggressive","combative","belligerent"]', '["cooperative","friendly","amiable"]', 'The truculent behavior of the mob forced the district police to call for backup.', 'CSS Vocab', true),

  ('vocab-105', 'Pusillanimous', 'Showing a lack of courage or determination; timid.', 'بزدل / ڈرپوک (Buzdil / Darpook)', '["timid","cowardly","fearful","spineless"]', '["brave","courageous","valiant","intrepid"]', 'A pusillanimous approach to economic reforms will not resolve the ongoing debt crisis in the country.', 'CSS Vocab', true),

  ('vocab-106', 'Inveterate', 'Having a particular habit, activity, or interest that is long-established and unlikely to change.', 'پختہ / کٹر / پرانا (Pukhta / Kattar / Purana)', '["ingrained","deep-seated","habitual","chronic"]', '["temporary","occasional","transient"]', 'He was an inveterate reader of the Dawn editorial page, which greatly aided his CSS English composition preparation.', 'CSS Vocab', true),

  ('vocab-107', 'Malfeasance', 'Wrongdoing, especially by a public official.', 'بدعنوانی / غیر قانونی کام (Bad-unwani / Ghayr qanooni kaam)', '["wrongdoing","misconduct","corruption","impropriety"]', '["propriety","honesty","obedience"]', 'The anti-corruption establishment launched an inquiry into the alleged financial malfeasance in the public works department.', 'CSS Vocab', true),

  ('vocab-108', 'Perfidious', 'Deceitful and untrustworthy.', 'دھوکے باز / بے وفا (Dhokay-baaz / Be-wafa)', '["treacherous","deceitful","disloyal","two-faced"]', '["faithful","loyal","trustworthy","dependable"]', 'The diplomat warned against signing the bilateral trade agreement with a historically perfidious neighboring state.', 'CSS Vocab', true),

  ('vocab-109', 'Supercilious', 'Behaving or looking as though one thinks one is superior to others.', 'مغرور / متکبر (Maghroor / Mutakabir)', '["arrogant","haughty","conceited","pompous"]', '["humble","modest","unassuming"]', 'The senior bureaucrat''s supercilious attitude alienated the junior staff working under him in the secretariat.', 'CSS Vocab', true),

  ('vocab-110', 'Turpitude', 'Depravity; wickedness.', 'ذلالت / بدکاری (Zalalat / Badkari)', '["depravity","corruption","wickedness","baseness"]', '["virtue","decency","goodness","morality"]', 'The judge noted that the level of moral turpitude displayed by the smugglers warranted the maximum penalty.', 'CSS Vocab', true),

  ('vocab-111', 'Vituperate', 'Blame or insult (someone) in strong or violent language.', 'گالیاں دینا / ملامت کرنا (Galiyan dena / Malamat karna)', '["scold","revile","upbraid","reprimand"]', '["praise","commend","laud","extol"]', 'During the assembly session, opposition members began to vituperate the finance minister over the sudden petrol price hike.', 'CSS Vocab', true),

  ('vocab-112', 'Inimical', 'Tending to obstruct or harm; unfriendly, hostile.', 'دشمنانہ / نقصان دہ (Dushmanana / Nuqsan-deh)', '["harmful","injurious","hostile","detrimental"]', '["friendly","favorable","advantageous"]', 'Rampant inflation and high interest rates are fundamentally inimical to the growth of the manufacturing sector.', 'CSS Vocab', true),

  ('vocab-113', 'Insolent', 'Showing a rude and arrogant lack of respect.', 'گستاخ / بدتمیز (Gustakh / Bad-tameez)', '["impertinent","impudent","cheeky","disrespectful"]', '["polite","respectful","deferential"]', 'The candidate was immediately disqualified from the interview for making an insolent remark to the panel chairman.', 'CSS Vocab', true),

  ('vocab-114', 'Litigious', 'Unreasonably prone to go to law to settle disputes.', 'مقدمہ باز (Muqadma-baaz)', '["argumentative","contentious","disputatious"]', '["peaceable","agreeable","easygoing"]', 'The land dispute dragged on for decades because both rival clans were notoriously litigious.', 'CSS Vocab', true),

  ('vocab-115', 'Temerity', 'Excessive confidence or boldness; audacity.', 'جرات / گستاخی (Jurat / Gustakhi)', '["audacity","nerve","effrontery","impudence"]', '["shyness","bashfulness","timidity"]', 'None of the junior clerks had the temerity to question the controversial directives issued by the section officer.', 'CSS Vocab', true),

  ('vocab-116', 'Avarice', 'Extreme greed for wealth or material gain.', 'لالچ / طمع (Lalach / Tama)', '["greed","acquisitiveness","cupidity","rapacity"]', '["generosity","philanthropy","charity"]', 'The auditor''s report revealed that corporate avarice was the root cause of the pharmaceutical supply shortage.', 'CSS Vocab', true),

  ('vocab-117', 'Propitious', 'Giving or indicating a good chance of success; favorable.', 'سازگار / موافق (Sazgaar / Muwafiq)', '["favorable","auspicious","promising","optimistic"]', '["inauspicious","unfavorable","unpromising"]', 'The approval of the IMF bailout package created a propitious environment for foreign direct investment.', 'CSS Vocab', true),

  ('vocab-118', 'Sanguine', 'Optimistic or positive, especially in an apparently bad or difficult situation.', 'پرامید / رجائیت پسند (Pur-umeed / Rajaiyat-pasand)', '["optimistic","hopeful","buoyant","positive"]', '["pessimistic","gloomy","despondent"]', 'Despite early market fluctuations, the financial analyst remained sanguine that the Lucky Cement (LUCK) share price would stabilize around Rs. 437.', 'CSS Vocab', true),

  ('vocab-119', 'Torpor', 'A state of physical or mental inactivity; lethargy.', 'سستی / غفلت (Susti / Ghaflat)', '["lethargy","sluggishness","inertia","apathy"]', '["vigor","energy","animation"]', 'The intense summer heat in Multan induced a collective torpor among the students preparing for their final CSS mock exams.', 'CSS Vocab', true),

  ('vocab-120', 'Umbrage', 'Offense or annoyance.', 'ناراضگی / خفگی (Narazgi / Khafgi)', '["offense","indignation","annoyance","resentment"]', '["pleasure","delight","satisfaction"]', 'The provincial minister took umbrage at the journalist''s probing questions regarding the uncompleted infrastructure projects.', 'CSS Vocab', true),

  ('vocab-121', 'Veracious', 'Speaking or representing the truth.', 'سچا / راست باز (Sacha / Raast-baaz)', '["truthful","honest","accurate","reliable"]', '["mendacious","false","deceitful"]', 'The investigation committee required veracious testimonies from the eyewitnesses to finalize the ETEA paper leak report.', 'CSS Vocab', true),

  ('vocab-122', 'Ostentatious', 'Characterized by vulgar or pretentious display; designed to impress or attract notice.', 'دکھاوے کا / پر تکلف (Dikhaway ka / Pur-takalluf)', '["showy","pretentious","conspicuous","flamboyant"]', '["modest","unobtrusive","plain"]', 'In a departure from ostentatious designs, the web developer limited the portfolio PRD strictly to a clean glassmorphism hero and project display.', 'CSS Vocab', true),

  ('vocab-123', 'Ignominious', 'Deserving or causing public disgrace or shame.', 'شرمناک / رسوا کن (Sharmnak / Ruswa-kun)', '["humiliating","undignified","embarrassing","disgraceful"]', '["glorious","honorable","respectable"]', 'The militant group suffered an ignominious defeat following the targeted operation by the security forces.', 'CSS Vocab', true),

  ('vocab-124', 'Repudiate', 'Refuse to accept or be associated with.', 'مسترد کرنا / انکار کرنا (Mustarad karna / Inkar karna)', '["reject","renounce","abandon","dismiss"]', '["embrace","accept","acknowledge"]', 'The newly elected government moved swiftly to repudiate the controversial treaties signed by the previous administration.', 'CSS Vocab', true),

  ('vocab-125', 'Obsequious', 'Obedient or attentive to an excessive or servile degree.', 'خوشامدی / چاپلوس (Khushamdi / Chaploos)', '["servile","fawning","sycophantic","submissive"]', '["domineering","arrogant","assertive"]', 'The obsequious behavior of the junior officers toward the inspector general was visibly uncomfortable for the independent observers.', 'CSS Vocab', true),

  ('vocab-126', 'Recondite', 'Little known; abstruse.', 'پوشیدہ / گہرا (Poshida / Gehra)', '["obscure","arcane","esoteric","profound"]', '["straightforward","simple","familiar"]', 'The PMS general knowledge paper included highly recondite details about the pre-partition municipal laws.', 'CSS Vocab', true),

  ('vocab-127', 'Castigate', 'Reprimand (someone) severely.', 'سخت تنقید کرنا / سزا دینا (Sakht tanqeed karna / Saza dena)', '["reprimand","rebuke","admonish","chastise"]', '["praise","commend","approve"]', 'The Supreme Court judge proceeded to castigate the investigation officer for presenting a severely flawed forensic report.', 'CSS Vocab', true),

  ('vocab-128', 'Chicanery', 'The use of trickery to achieve a political, financial, or legal purpose.', 'دھوکہ دہی / فریب (Dhoka-dahi / Fareb)', '["trickery","deception","deceit","sophistry"]', '["honesty","truthfulness","candor"]', 'The election tribunal disqualified the candidate after discovering widespread political chicanery in the postal ballot counting.', 'CSS Vocab', true),

  ('vocab-129', 'Diatribe', 'A forceful and bitter verbal attack against someone or something.', 'سخت تنقید / زہر آلود تقریر (Sakht tanqeed / Zehar-aalood taqreer)', '["tirade","harangue","onslaught","condemnation"]', '["compliment","praise","eulogy"]', 'The opposition leader launched a blistering diatribe against the ruling party''s handling of the national circular debt.', 'CSS Vocab', true),

  ('vocab-130', 'Dirge', 'A lament for the dead, especially one forming part of a funeral rite.', 'نوحہ / ماتمی گیت (Noha / Matmi geet)', '["elegy","lament","requiem"]', '["anthem","paean"]', 'The solemn military band played a moving dirge as the martyred soldiers were laid to rest.', 'CSS Vocab', true),

  ('vocab-131', 'Disabuse', 'Persuade (someone) that an idea or belief is mistaken.', 'غلط فہمی دور کرنا (Ghalat fehmi door karna)', '["undeceive","enlighten","correct"]', '["deceive","mislead","delude"]', 'The CSS mentor quickly stepped in to disabuse the aspirants of the notion that merely memorizing vocabulary lists guarantees a passing score.', 'CSS Vocab', true),

  ('vocab-132', 'Disparate', 'Essentially different in kind; not allowing comparison.', 'مختلف / بے جوڑ (Mukhtalif / Be-jorr)', '["contrasting","different","differing","dissimilar"]', '["homogeneous","similar","identical"]', 'Unifying the disparate ethnic and political factions within the province remains a significant challenge for the chief minister.', 'CSS Vocab', true),

  ('vocab-133', 'Dissemble', 'Conceal one''s true motives, feelings, or beliefs.', 'بھینس بدلنا / چھپانا (Bhais badalna / Chhupana)', '["pretend","deceive","feign","masquerade"]', '["reveal","disclose","expose"]', 'During the cross-examination by the FIA, the embezzler tried to dissemble his involvement in the offshore shell companies.', 'CSS Vocab', true),

  ('vocab-134', 'Efficacy', 'The ability to produce a desired or intended result.', 'اثر پذیری / تاثیر (Asar-pazeeri / Taseer)', '["effectiveness","success","potency","power"]', '["inefficacy","inability","failure"]', 'The health department published statistical data proving the efficacy of the new anti-polio vaccination drive.', 'CSS Vocab', true),

  ('vocab-135', 'Elegy', 'A poem of serious reflection, typically a lament for the dead.', 'مرثیہ / سوگوار نظم (Marsiya / Sogwaar nazm)', '["lament","dirge","requiem","plaint"]', '["paean","celebration"]', 'The renowned Urdu poet recited a heart-wrenching elegy dedicated to the victims of the devastating earthquake.', 'CSS Vocab', true),

  ('vocab-136', 'Admonish', 'To warn or reprimand someone firmly.', 'ڈانٹنا / سرزنش کرنا (Dantna / Sarzanish karna)', '["reprimand","rebuke","scold","chastise"]', '["praise","commend","approve","laud"]', 'The KPPSC examiner admonished candidates caught attempting to communicate during the screening test.', 'KPPSC Vocab', true),

  ('vocab-137', 'Appease', 'Pacify or placate (someone) by acceding to their demands.', 'راضی کرنا / تسلی دینا (Raazi karna / Tasalli dena)', '["conciliate","placate","pacify","mollify"]', '["provoke","inflame","enrage"]', 'The local administration distributed relief packages to appease the protestors blockading the national highway.', 'KPPSC Vocab', true),

  ('vocab-138', 'Acumen', 'The ability to make good judgments and quick decisions, typically in a particular domain.', 'ذہانت / فراست (Zahanat / Farasat)', '["astuteness","shrewdness","sharpness","insight"]', '["ignorance","stupidity","ineptness"]', 'His technical acumen was evident when he successfully secured a score of 57 out of 100 on the difficult ETEA Computer Operator technical examination.', 'KPPSC Vocab', true),

  ('vocab-139', 'Candid', 'Truthful and straightforward; frank.', 'کھرا / صاف گو (Khara / Saaf-go)', '["frank","outspoken","forthright","blunt"]', '["secretive","guarded","insincere"]', 'During the panel interview, she gave a candid assessment of the flaws in the current local government system.', 'KPPSC Vocab', true),

  ('vocab-140', 'Compliant', 'Inclined to agree with others or obey rules, especially to an excessive degree.', 'فرمانبردار / تابع دار (Farmanbardar / Taba-dar)', '["acquiescent","amenable","tractable","yielding"]', '["recalcitrant","rebellious","stubborn"]', 'The imported machinery must be fully compliant with the regulatory standards set by the federal engineering board.', 'KPPSC Vocab', true),

  ('vocab-141', 'Connive', 'Secretly allow (something considered immoral, illegal, or wrong) to occur.', 'چشم پوشی کرنا / ساز باز کرنا (Chashm-poshi karna / Saaz-baaz karna)', '["collude","conspire","overlook","ignore"]', '["condemn","oppose","prevent"]', 'The internal audit revealed that several floor supervisors had connived to bypass the biometric attendance system.', 'KPPSC Vocab', true),

  ('vocab-142', 'Corroborate', 'Confirm or give support to (a statement, theory, or finding).', 'تصدیق کرنا / تائید کرنا (Tasdeeq karna / Taeed karna)', '["verify","endorse","validate","authenticate"]', '["contradict","refute","deny"]', 'The CCTV footage was used by the police to corroborate the victim''s timeline of events in the FIR.', 'KPPSC Vocab', true),

  ('vocab-143', 'Delude', 'Impose a misleading belief upon (someone); deceive; fool.', 'دھوکہ دینا / گمراہ کرنا (Dhoka dena / Gumrah karna)', '["mislead","deceive","fool","trick"]', '["enlighten","clarify","guide"]', 'Aspirants should not delude themselves into thinking that provincial management exams can be cleared without rigorous daily writing practice.', 'KPPSC Vocab', true),

  ('vocab-144', 'Denounce', 'Publicly declare to be wrong or evil.', 'مذمت کرنا / کھلے عام برائی کرنا (Muzamat karna / Khulay aam burai karna)', '["condemn","criticize","attack","censure"]', '["praise","extol","commend"]', 'The human rights commission issued a strong statement to denounce the extrajudicial actions taken during the raid.', 'KPPSC Vocab', true),

  ('vocab-145', 'Destitute', 'Without the basic necessities of life.', 'مفلس / محتاج (Muflis / Mohtaj)', '["penniless","impoverished","poor","indigent"]', '["wealthy","affluent","prosperous"]', 'The devastating monsoon floods left thousands of families destitute in the southern districts of the province.', 'KPPSC Vocab', true),

  ('vocab-146', 'Discrepancy', 'An illogical or surprising lack of compatibility or similarity between two or more facts.', 'تضاد / فرق (Tazad / Farq)', '["inconsistency","difference","variance","disparity"]', '["consistency","agreement","similarity"]', 'The auditor flagged a massive financial discrepancy between the allocated budget and the actual expenditure on the dam project.', 'KPPSC Vocab', true),

  ('vocab-147', 'Elude', 'Evade or escape from (a danger, enemy, or pursuer), typically in a skillful or cunning way.', 'بچ نکلنا / فرار ہونا (Bach nikalna / Faraar hona)', '["evade","avoid","dodge","escape"]', '["encounter","face","confront"]', 'The notorious smuggling ring managed to elude customs officials along the border for several years.', 'KPPSC Vocab', true),

  ('vocab-148', 'Empower', 'Give (someone) the authority or power to do something.', 'بااختیار بنانا (Ba-ikhtiyar banana)', '["authorize","entitle","permit","enable"]', '["disempower","forbid","prevent"]', 'The new civil service reforms were designed to empower young officers at the district administration level.', 'KPPSC Vocab', true),

  ('vocab-149', 'Entrust', 'Assign the responsibility for doing something to (someone).', 'سونپنا / حوالے کرنا (Saunpna / Hawalay karna)', '["assign","delegate","confide","commit"]', '["withhold","keep","retain"]', 'Given his reliable nature, he would proactively entrust his distributed web development earnings to support his parents and overall household budget.', 'KPPSC Vocab', true),

  ('vocab-150', 'Exacerbate', 'Make (a problem, bad situation, or negative feeling) worse.', 'بدتر بنانا / شدت پیدا کرنا (Bad-tar banana / Shiddat paida karna)', '["aggravate","worsen","inflame","compound"]', '["alleviate","mitigate","reduce"]', 'Cutting off internet services will only exacerbate the existing panic and spread of misinformation.', 'KPPSC Vocab', true),

  ('vocab-151', 'Expedite', 'Make (an action or process) happen sooner or be accomplished more quickly.', 'تیز کرنا / جلدی نمٹانا (Tez karna / Jaldi nimtana)', '["accelerate","hasten","speed up","precipitate"]', '["delay","hinder","retard"]', 'The IT administrator deployed custom Next.js server rules to expedite the SSL propagation process for the academy''s new domain.', 'KPPSC Vocab', true),

  ('vocab-152', 'Grievance', 'A real or imagined wrong or other cause for complaint or protest, especially unfair treatment.', 'شکایت / گلہ (Shikayat / Gila)', '["complaint","injustice","wrong","resentment"]', '["compliment","praise","benefit"]', 'The labor union formally submitted a list of their grievance regarding delayed pension disbursements to the secretariat.', 'KPPSC Vocab', true),

  ('vocab-153', 'Hinder', 'Create difficulties for (someone or something), resulting in delay or obstruction.', 'رکاوٹ ڈالنا / منع کرنا (Rukawat dalna / Mana karna)', '["impede","obstruct","hamper","delay"]', '["facilitate","help","assist"]', 'Heavy snowfall in the upper valleys continued to hinder the deployment of election materials to remote polling stations.', 'KPPSC Vocab', true),

  ('vocab-154', 'Impede', 'Delay or prevent (someone or something) by obstructing them; hinder.', 'رکاوٹ بننا / باز رکھنا (Rukawat banna / Baaz rakhna)', '["hinder","obstruct","hamper","disrupt"]', '["facilitate","advance","encourage"]', 'Bureaucratic red tape continues to impede the swift execution of foreign direct investment projects in the region.', 'KPPSC Vocab', true),

  ('vocab-155', 'Impartial', 'Treating all rivals or disputants equally; fair and just.', 'غیر جانبدار / منصفانہ (Ghayr janibdar / Munsifana)', '["unbiased","neutral","objective","fair"]', '["biased","prejudiced","partisan"]', 'The testing agency is legally bound to conduct a completely impartial screening process for all gazetted positions.', 'KPPSC Vocab', true),

  ('vocab-156', 'Mandate', 'An official order or commission to do something.', 'حکم نامہ / اختیار (Hukam-nama / Ikhtiyar)', '["directive","decree","command","authorization"]', '["denial","veto","refusal"]', 'The newly elected mayor claimed a strong public mandate to completely overhaul the city''s failing sanitation systems.', 'KPPSC Vocab', true),

  ('vocab-157', 'Mitigate', 'Make less severe, serious, or painful.', 'کم کرنا / ہلکا کرنا (Kam karna / Halka karna)', '["alleviate","reduce","diminish","lessen"]', '["aggravate","exacerbate","intensify"]', 'The provincial disaster management authority built embankments to mitigate the risk of annual river flooding.', 'KPPSC Vocab', true),

  ('vocab-158', 'Obscure', 'Not discovered or known about; uncertain.', 'مبہم / غیر واضح (Mubham / Ghayr wazeh)', '["unclear","vague","doubtful","hidden"]', '["clear","obvious","prominent"]', 'The examiner purposely included an obscure reference to a 19th-century treaty to test the absolute top-tier candidates.', 'KPPSC Vocab', true),

  ('vocab-159', 'Partisan', 'A strong supporter of a party, cause, or person; prejudiced in favor of a particular cause.', 'جانبدار / حامی (Janibdar / Haami)', '["supporter","follower","biased","prejudiced"]', '["impartial","neutral","unbiased"]', 'The journalist''s fiercely partisan coverage of the judicial reforms drew heavy criticism from independent legal observers.', 'KPPSC Vocab', true),

  ('vocab-160', 'Prudent', 'Acting with or showing care and thought for the future.', 'محتاط / دور اندیش (Mohtat / Door-andesh)', '["wise","sensible","cautious","judicious"]', '["reckless","careless","foolish"]', 'It is prudent for serious job seekers to continuously attempt mock exams rather than waiting for the final roll number slip.', 'KPPSC Vocab', true),

  ('vocab-161', 'Abdicate', 'Fail to fulfill or undertake (a responsibility or duty), or renounce one''s throne.', 'دستبردار ہونا / چھوڑ دینا (Dastbardar hona / Chhor dena)', '["resign","retire","quit","renounce"]', '["accept","assume","retain"]', 'The minister was pressured to abdicate his portfolio following the severe public backlash against the recent policy failures.', 'FPSC Vocab', true),

  ('vocab-162', 'Acquiesce', 'Accept something reluctantly but without protest.', 'رضامند ہونا / خاموشی سے مان لینا (Razamand hona / Khamoshi se maan lena)', '["consent","submit","comply","agree"]', '["resist","oppose","refuse"]', 'Faced with undeniable forensic evidence, the suspect had no choice but to acquiesce to the federal investigators'' demands.', 'FPSC Vocab', true),

  ('vocab-163', 'Ambivalent', 'Having mixed feelings or contradictory ideas about something or someone.', 'تذبذب کا شکار / دوہری سوچ والا (Tazabzub ka shikar / Dohri soch wala)', '["uncertain","unsure","undecided","conflicted"]', '["certain","unequivocal","resolute"]', 'Many economists remain ambivalent about whether the aggressive taxation policy will ultimately stabilize or crush local manufacturing.', 'FPSC Vocab', true),

  ('vocab-164', 'Audacious', 'Showing a willingness to take surprisingly bold risks.', 'نڈر / بے باک (Nadar / Be-baak)', '["bold","daring","fearless","brave"]', '["timid","cowardly","cautious"]', 'Applying for the rigorous Assistant Sub-Inspector physical and academic exams requires an audacious spirit and extreme dedication.', 'FPSC Vocab', true),

  ('vocab-165', 'Capitulate', 'Cease to resist an opponent or an unwelcome demand; surrender.', 'ہتھیار ڈالنا / ہار ماننا (Hathyar dalna / Haar manna)', '["surrender","yield","submit","concede"]', '["resist","fight","defend"]', 'After weeks of intense military pressure, the insurgent commanders agreed to capitulate and hand over their illegal weapons.', 'FPSC Vocab', true),

  ('vocab-166', 'Censure', 'Express severe disapproval of (someone or something), especially in a formal statement.', 'سخت تنقید / مذمت (Sakht tanqeed / Muzamat)', '["condemnation","criticism","reprimand","rebuke"]', '["approval","praise","commendation"]', 'The foreign office issued a strong note of censure against the unprovoked cross-border violations by the neighboring state.', 'FPSC Vocab', true),

  ('vocab-167', 'Coerce', 'Persuade (an unwilling person) to do something by using force or threats.', 'مجبور کرنا / زبردستی کرنا (Majboor karna / Zabardasti karna)', '["force","compel","pressure","intimidate"]', '["persuade","encourage","coax"]', 'The syndicate attempted to coerce local business owners into paying extortion money under the guise of security fees.', 'FPSC Vocab', true),

  ('vocab-168', 'Compel', 'Force or oblige (someone) to do something.', 'مجبور کرنا (Majboor karna)', '["force","coerce","oblige","require"]', '["allow","permit","let"]', 'The updated transparency act will compel all high-ranking officials to publicly declare their domestic and foreign assets.', 'FPSC Vocab', true),

  ('vocab-169', 'Connivance', 'Willingness to secretly allow or be involved in wrongdoing, especially an immoral or illegal act.', 'ساز باز / چشم پوشی (Saaz-baaz / Chashm-poshi)', '["collusion","complicity","involvement","assistance"]', '["ignorance","opposition"]', 'The illegal deforestation in the northern areas could only have continued with the active connivance of local forestry officials.', 'FPSC Vocab', true),

  ('vocab-170', 'Contrition', 'The state of feeling remorseful and penitent.', 'پچھتاوا / ندامت (Pachtawa / Nadamat)', '["remorse","repentance","sorrow","penitence"]', '["impenitence","defiance","indifference"]', 'Despite pleading guilty, the accused showed absolutely no signs of contrition during his sentencing hearing at the high court.', 'FPSC Vocab', true),

  ('vocab-171', 'Culpable', 'Deserving blame.', 'مجرم / قابلِ سزا (Mujrim / Qabil-e-saza)', '["guilty","blameworthy","accountable","liable"]', '["innocent","blameless","immune"]', 'The investigation concluded that both the contractor and the project supervisor were highly culpable for the bridge collapse.', 'FPSC Vocab', true),

  ('vocab-172', 'Defiant', 'Showing defiance; openly resisting.', 'نافرمان / باغی (Nafarman / Baghi)', '["intransigent","resistant","obstinate","rebellious"]', '["submissive","obedient","cooperative"]', 'The defiant protest leaders refused to vacate the capital''s main square despite repeated police warnings.', 'FPSC Vocab', true),

  ('vocab-173', 'Deference', 'Humble submission and respect.', 'احترام / تابعداری (Ehtiram / Tabedari)', '["respect","submission","reverence","compliance"]', '["disrespect","disobedience","insolence"]', 'In traditional bureaucratic culture, junior officers are expected to show absolute deference to their senior civil servants.', 'FPSC Vocab', true),

  ('vocab-174', 'Duplicity', 'Deceitfulness; double-dealing.', 'دوغلا پن / منافقت (Doghla-pan / Munafiqat)', '["deceit","deception","treachery","dishonesty"]', '["honesty","straightforwardness","sincerity"]', 'The ambassador accused the foreign delegation of severe diplomatic duplicity regarding the newly proposed regional peace treaty.', 'FPSC Vocab', true),

  ('vocab-175', 'Embargo', 'An official ban on trade or other commercial activity with a particular country.', 'تجارتی پابندی / امتناع (Tijarti pabandi / Imtina)', '["ban","restriction","prohibition","boycott"]', '["allowance","permission","clearance"]', 'The sudden implementation of a strict import embargo heavily impacted the local automotive assembly sector.', 'FPSC Vocab', true),

  ('vocab-176', 'Fervent', 'Having or displaying a passionate intensity.', 'پرجوش / سرگرم (Pur-josh / Sargarm)', '["passionate","intense","vehement","ardent"]', '["apathetic","indifferent","lukewarm"]', 'She was a fervent advocate for women''s education, working relentlessly across rural districts to establish new public schools.', 'FPSC Vocab', true),

  ('vocab-177', 'Flagrant', 'Of something considered wrong or immoral, conspicuously or obviously offensive.', 'کھلا / صریح (Khula / Sareeh)', '["blatant","glaring","obvious","shameless"]', '["hidden","concealed","subtle"]', 'The construction of the commercial plaza on designated park land was a flagrant violation of the capital''s zoning laws.', 'FPSC Vocab', true),

  ('vocab-178', 'Impunity', 'Exemption from punishment or freedom from the injurious consequences of an action.', 'سزا سے چھوٹ / استثنیٰ (Saza se chhoot / Istasna)', '["exemption","immunity","indemnity","amnesty"]', '["liability","responsibility","vulnerability"]', 'No individual, regardless of their political connections, should be allowed to operate illegal housing societies with impunity.', 'FPSC Vocab', true),

  ('vocab-179', 'Lament', 'A passionate expression of grief or sorrow.', 'نوحہ / ماتم کرنا (Noha / Matam karna)', '["mourn","grieve","sorrow","bemoan"]', '["celebrate","rejoice","cheer"]', 'Economists continue to lament the structural deficiencies that plague the national tax collection system year after year.', 'FPSC Vocab', true),

  ('vocab-180', 'Magnanimous', 'Generous or forgiving, especially toward a rival or less powerful person.', 'فراخ دل / عالی ظرف (Farakh-dil / Aali zarf)', '["generous","charitable","noble","forgiving"]', '["selfish","mean","vindictive"]', 'In a truly magnanimous gesture, the winning candidate publicly thanked his opponents and urged for post-election unity.', 'FPSC Vocab', true),

  ('vocab-181', 'Abolish', 'Formally put an end to (a system, practice, or institution).', 'ختم کرنا / منسوخ کرنا (Khatam karna / Mansookh karna)', '["eliminate","eradicate","terminate","annul"]', '["establish","create","institute"]', 'There is a growing public demand to completely abolish outdated colonial-era laws governing municipal taxation.', 'General Vocabulary', true),

  ('vocab-182', 'Abrupt', 'Sudden and unexpected.', 'اچانک / غیر متوقع (Achanak / Ghayr mutawaqqa)', '["sudden","unexpected","hasty","precipitate"]', '["gradual","expected","leisurely"]', 'The abrupt transfer of the District Police Officer raised several questions among the local journalist community.', 'General Vocabulary', true),

  ('vocab-183', 'Abundant', 'Existing or available in large quantities; plentiful.', 'وافر / کثیر (Wafir / Kaseer)', '["plentiful","copious","ample","profuse"]', '["scarce","rare","lacking"]', 'Pakistan possesses abundant natural resources that require strategic planning to fully harness for economic growth.', 'General Vocabulary', true),

  ('vocab-184', 'Accord', 'Give or grant someone (power, status, or recognition).', 'معاہدہ / متفق ہونا (Muahida / Muttafiq hona)', '["agreement","harmony","pact","treaty"]', '["disagreement","discord","conflict"]', 'The two rival factions finally reached a historic peace accord facilitated by the provincial mediation committee.', 'General Vocabulary', true),

  ('vocab-185', 'Accumulate', 'Gather together or acquire an increasing number or quantity of.', 'جمع کرنا / اکٹھا کرنا (Jama karna / Ikatha karna)', '["amass","gather","collect","hoard"]', '["disperse","dissipate","squander"]', 'It is vital for serious CSS candidates to accumulate a vast reservoir of general knowledge well before the written exams.', 'General Vocabulary', true),

  ('vocab-186', 'Accuracy', 'The quality or state of being correct or precise.', 'درستگی / صحت (Durustagi / Sehat)', '["precision","exactness","correctness","truthfulness"]', '["inaccuracy","error","mistake"]', 'Data entry tasks in government digitization initiatives demand a very high level of typing speed and absolute accuracy.', 'General Vocabulary', true),

  ('vocab-187', 'Adept', 'Very skilled or proficient at something.', 'ماہر / مشاق (Mahir / Mashaaq)', '["skilled","proficient","expert","masterful"]', '["inept","clumsy","amateur"]', 'The intelligence operative proved extremely adept at decoding the encrypted communications intercepted during the raid.', 'General Vocabulary', true),

  ('vocab-188', 'Adhere', 'Stick fast to (a surface or substance); believe in and follow the practices of.', 'ثابت قدم رہنا / چپکنا (Sabit qadam rehna / Chipakna)', '["stick","cling","attach","comply"]', '["detach","separate","ignore"]', 'All public servants are legally obligated to strictly adhere to the official code of conduct and ethics.', 'General Vocabulary', true),

  ('vocab-189', 'Adversary', 'One''s opponent in a contest, conflict, or dispute.', 'دشمن / حریف (Dushman / Hareef)', '["opponent","rival","enemy","foe"]', '["ally","friend","supporter"]', 'He respected his political adversary but heavily criticized his economic policies during the televised pre-election debate.', 'General Vocabulary', true),

  ('vocab-190', 'Adverse', 'Preventing success or development; harmful; unfavorable.', 'مخالف / نقصان دہ (Mukhalif / Nuqsan-deh)', '["unfavorable","disadvantageous","hostile","harmful"]', '["favorable","advantageous","beneficial"]', 'The agriculture sector suffered a severe decline due to adverse weather conditions and delayed monsoon rains this year.', 'General Vocabulary', true),

  ('vocab-191', 'Affable', 'Friendly, good-natured, or easy to talk to.', 'خوش اخلاق / ملنسار (Khush-ikhlaq / Milansaar)', '["friendly","amiable","genial","cordial"]', '["unfriendly","hostile","surly"]', 'The newly appointed commissioner was known for his affable demeanor, making him highly accessible to the general public.', 'General Vocabulary', true),

  ('vocab-192', 'Aggregate', 'A whole formed by combining several (typically disparate) elements.', 'مجموعہ / کل (Majmooa / Kul)', '["total","combined","cumulative","mass"]', '["individual","particular","separate"]', 'Your final merit position will be determined by the aggregate score of both your written exam and the psychological interview.', 'General Vocabulary', true),

  ('vocab-193', 'Allege', 'Claim or assert that someone has done something illegal or wrong, typically without proof that this is the case.', 'الزام لگانا (Ilzam lagana)', '["claim","assert","charge","accuse"]', '["deny","withdraw","retract"]', 'The opposition party continues to allege that widespread pre-poll rigging severely compromised the election results.', 'General Vocabulary', true),

  ('vocab-194', 'Allocate', 'Distribute (resources or duties) for a particular purpose.', 'مختص کرنا / بانٹنا (Mukhtas karna / Bantna)', '["assign","distribute","apportion","designate"]', '["withhold","keep","retain"]', 'He successfully managed to allocate a specific portion of his monthly savings to subscribe for 500 shares of the SLM IPO.', 'General Vocabulary', true),

  ('vocab-195', 'Ambition', 'A strong desire to do or to achieve something, typically requiring determination and hard work.', 'عزائم / مقصد (Azaim / Maqsad)', '["aspiration","goal","objective","desire"]', '["apathy","laziness","indifference"]', 'Her ultimate ambition was to pass the CSS exam and serve the nation as an honest officer in the Police Service of Pakistan.', 'General Vocabulary', true),

  ('vocab-196', 'Aptitude', 'A natural ability to do something.', 'رجحان / فطری صلاحیت (Rujhan / Fitri salahiyat)', '["ability","talent","capability","skill"]', '["inability","incompetence","ineptitude"]', 'The initial ETEA screening test is designed purely to measure a candidate''s general intellectual and mathematical aptitude.', 'ETEA Vocab', true),

  ('vocab-197', 'Competent', 'Having the necessary ability, knowledge, or skill to do something successfully.', 'اہل / قابل (Ahal / Qabil)', '["capable","proficient","adept","qualified"]', '["incompetent","inept","unqualified"]', 'The department urgently requires a highly competent web developer to maintain and secure its official online portals.', 'ETEA Vocab', true),

  ('vocab-198', 'Deduce', 'Arrive at (a fact or a conclusion) by reasoning; draw as a logical conclusion.', 'نتیجہ اخذ کرنا (Nateeja akhaz karna)', '["infer","conclude","reason","gather"]', '["guess","misunderstand","ignore"]', 'From the fragmented historical records, the examiner expected candidates to deduce the socio-economic impacts of the 1857 war.', 'ETEA Vocab', true),

  ('vocab-199', 'Evaluate', 'Form an idea of the amount, number, or value of; assess.', 'جائزہ لینا / تخمینہ لگانا (Jaiza lena / Takhmeena lagana)', '["assess","appraise","judge","calculate"]', '["neglect","ignore"]', 'The Federal Public Service Commission panel will rigorously evaluate your leadership skills and emotional stability during the interview phase.', 'ETEA Vocab', true),

  ('vocab-200', 'Formulate', 'Create or devise methodically (a strategy or a proposal).', 'ترتیب دینا / وضع کرنا (Tarteeb dena / Waza karna)', '["devise","conceive","develop","create"]', '["destroy","ruin","dismantle"]', 'The national economic council must formulate a concrete, actionable policy to tackle the rising inflation rates.', 'ETEA Vocab', true)

